// 快捷函数：构建去AI味 prompt
export function buildRemoveAIPrompt(
  selectedText: string,
  context: {
    facts?: string
    characters?: string
  }
): string {
  const task = TASKS.removeAITrace
  const contextBlock = buildContextBlock({
    chapterContent: '',
    facts: context.facts,
    characters: context.characters,
  })

  const prompt = task.task.replace('{selectedText}', selectedText)
  return task.role_persona + '\n\n' + contextBlock + '\n' + prompt
}

// 快捷函数：构建节奏检测 prompt
export function buildRhythmCheckPrompt(
  chapterContent: string,
  chapterRange: { start: number; end: number }
): string {
  const task = TASKS.rhythmCheck
  const contextBlock = buildContextBlock({
    chapterContent,
    chapterRange,
  })

  return task.role_persona + '\n\n' + contextBlock + '\n' + task.task
}

